@contextmanager
def undo_record(app, name: str = "IA_Word operation"):
    """Wrap COM mutations in a single Word UndoRecord (one Ctrl+Z to undo all).

    Degrades gracefully on Word 2007 or if UndoRecord is unavailable.
    """
    rec = None
    try:
        rec = app.UndoRecord
        if rec.IsRecordingCustomRecord:
            try:
                rec.EndCustomRecord()
            except Exception:
                pass
        rec.StartCustomRecord(name[:64])
    except Exception:
        rec = None
    try:
        yield
    finally:
        if rec is not None:
            try:
                rec.EndCustomRecord()
            except Exception:
                pass

